const __cache = {
  walks: new Map(),
  weather: new Map(),
  derived: new Map()
};
const MAX_CACHE_SIZE = 200;
const CACHE_MISS = Symbol("cache-miss");
const DEBUG_CACHE = false;

function debugCacheHit(type, key) {
  if (!DEBUG_CACHE) return;
  console.log("[CACHE HIT]", type, key);
}

function normalizeCacheMap(map) {
  if (!(map instanceof Map)) return false;
  if (map.size > MAX_CACHE_SIZE) {
    map.clear();
    return true;
  }
  return false;
}

function createVersionFromState(currentState) {
  const directVersion = normalizeSyncTimestamp(currentState?.lastUpdated || currentState?.version || "");
  if (directVersion) return directVersion;
  if (!currentState || typeof currentState !== "object") return "0";

  const collectionVersion = (items = []) => {
    const activeItems = activeSyncItems(items);
    let latestUpdated = "";
    activeItems.forEach((item) => {
      const candidate = localSyncRecordTimestamp(item);
      if (candidate > latestUpdated) {
        latestUpdated = candidate;
      }
    });
    return `${activeItems.length}_${latestUpdated}`;
  };

  return [
    collectionVersion(currentState.categories),
    collectionVersion(currentState.varieties),
    collectionVersion(currentState.customTasks),
    collectionVersion(currentState.journal)
  ].join("|");
}

function currentCacheVersion() {
  try {
    return createVersionFromState(state);
  } catch (error) {
    return "0";
  }
}

function setCache(map, key, value) {
  if (!(map instanceof Map)) return value;
  normalizeCacheMap(map);
  if (map.has(key)) {
    map.delete(key);
  } else if (map.size >= MAX_CACHE_SIZE) {
    const firstKey = map.keys().next().value;
    if (typeof firstKey !== "undefined") {
      map.delete(firstKey);
    }
  }
  map.set(key, value);
  return value;
}

function getCachedValue(map, key) {
  if (!(map instanceof Map)) return CACHE_MISS;
  if (normalizeCacheMap(map)) return CACHE_MISS;
  return map.has(key) ? map.get(key) : CACHE_MISS;
}

function clearAppCache() {
  __cache.walks.clear();
  __cache.weather.clear();
  __cache.derived.clear();
}

function walkGpsPointsCacheKey(points = []) {
  const safePoints = Array.isArray(points) ? points : [];
  if (!safePoints.length) return "0";
  if (safePoints.length > 100) {
    const firstPoint = safePoints[0] || null;
    const lastPoint = safePoints[safePoints.length - 1] || null;
    const firstStamp = String(firstPoint?.ts || firstPoint?.recordedAt || firstPoint?.timestamp || "").trim();
    const lastStamp = String(lastPoint?.ts || lastPoint?.recordedAt || lastPoint?.timestamp || "").trim();
    return `${safePoints.length}_${firstStamp}_${lastStamp}`;
  }
  return safePoints.map((point) => {
    const latitude = Number(point?.lat ?? point?.latitude);
    const longitude = Number(point?.lng ?? point?.lon ?? point?.longitude);
    const timestamp = String(point?.ts || point?.recordedAt || point?.timestamp || "").trim();
    const latLabel = Number.isFinite(latitude) ? latitude.toFixed(6) : "";
    const lngLabel = Number.isFinite(longitude) ? longitude.toFixed(6) : "";
    return `${latLabel},${lngLabel},${timestamp}`;
  }).join("|");
}

function walkWeatherCacheKey(weather = null) {
  if (!weather || typeof weather !== "object") return "";
  try {
    const originalKey = JSON.stringify({
      temperature: String(weather.temperature || "").trim(),
      wind: String(weather.wind || "").trim(),
      rain: String(weather.rain || "").trim(),
      condition: String(weather.condition || "").trim()
    });
    const cacheKey = `${currentCacheVersion()}_${originalKey}`;
    const cached = getCachedValue(__cache.weather, cacheKey);
    if (cached !== CACHE_MISS) {
      debugCacheHit("weather", cacheKey);
      return cached;
    }
    return setCache(__cache.weather, cacheKey, originalKey);
  } catch (error) {
    return [
      String(weather.temperature || "").trim(),
      String(weather.wind || "").trim(),
      String(weather.rain || "").trim(),
      String(weather.condition || "").trim()
    ].join("|");
  }
}

function walkSourceCacheKey(source = {}) {
  try {
    return JSON.stringify({
      startPlace: String(source?.startPlace || source?.start || "").trim(),
      endPlace: String(source?.endPlace || source?.end || "").trim(),
      startedAt: String(source?.startedAt || source?.started_at || "").trim(),
      endedAt: String(source?.endedAt || source?.ended_at || "").trim(),
      pausedAt: String(source?.pausedAt || source?.paused_at || "").trim(),
      pausedDurationMs: Math.max(0, Number(source?.pausedDurationMs || source?.paused_duration_ms || 0) || 0),
      distanceKm: source?.distanceKm ?? source?.distance ?? null,
      durationMinutes: source?.durationMinutes ?? source?.duration ?? null,
      routePoints: source?.routePoints?.length ? source.routePoints : (source?.routePointsText || source?.route || ""),
      gpsPoints: walkGpsPointsCacheKey(source?.gpsPoints),
      temperature: String(source?.temperature || "").trim(),
      wind: String(source?.wind || "").trim(),
      precipitation: String(source?.precipitation || source?.rain || "").trim(),
      conditions: String(source?.conditions || source?.condition || "").trim()
    });
  } catch (error) {
    return [
      String(source?.startPlace || source?.start || "").trim(),
      String(source?.endPlace || source?.end || "").trim(),
      String(source?.startedAt || source?.started_at || "").trim(),
      String(source?.endedAt || source?.ended_at || "").trim(),
      walkGpsPointsCacheKey(source?.gpsPoints)
    ].join("|");
  }
}

function normalizeSyncTimestamp(value = "") {
  return String(value || "").trim();
}

function normalizeSyncMediaStatus(value = "") {
  const normalized = String(value || "").trim().toLowerCase();
  return SYNC_MEDIA_STATUS_VALUES.has(normalized) ? normalized : "idle";
}

function isSyncEntityDeleted(item) {
  return Boolean(item?.deleted);
}

function activeSyncItems(items = []) {
  return (Array.isArray(items) ? items : []).filter((item) => !isSyncEntityDeleted(item));
}

function activeSyncCount(items = []) {
  return activeSyncItems(items).length;
}

function activeCategoryRecords() {
  return activeSyncItems(Array.isArray(state?.categories) ? state.categories : []);
}

function activeVarietyRecords() {
  return activeSyncItems(Array.isArray(state?.varieties) ? state.varieties : []);
}

function findActiveCategoryById(categoryId = "") {
  const normalizedId = String(categoryId || "").trim();
  if (!normalizedId) return null;
  return activeCategoryRecords().find((item) => item.id === normalizedId) || null;
}

function findActiveVarietyById(varietyId = "") {
  const normalizedId = String(varietyId || "").trim();
  if (!normalizedId) return null;
  return activeVarietyRecords().find((item) => item.id === normalizedId) || null;
}

function snapshotUndoStateValue() {
  return lastDeleted ? clone(lastDeleted) : null;
}

function restoreUndoStateSnapshot(snapshot = null) {
  if (snapshot && typeof snapshot === "object") {
    setUndoState(clone(snapshot));
    return;
  }
  clearUndoState();
}

function rollbackSoftDeleteResult(result = null) {
  if (!result?.changed || !result.collectionKey) return false;
  state[result.collectionKey] = Array.isArray(result.previousItems) ? result.previousItems : [];
  restoreUndoStateSnapshot(result.previousUndoState ?? null);
  return true;
}

function firstActiveCategoryId(categories = state?.categories || []) {
  return activeSyncItems(categories)[0]?.id || null;
}

function currentSeasonYear() {
  return new Date().getFullYear();
}

function normalizeSeasonYearValue(value, fallback = currentSeasonYear()) {
  const parsed = Number.parseInt(String(value ?? "").trim(), 10);
  if (Number.isFinite(parsed) && parsed >= 1900 && parsed <= 2100) return parsed;
  return fallback;
}

function extractSeasonYearFromDateValue(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return null;
  const normalized = raw.includes("T") ? raw : `${raw}T12:00:00`;
  const date = new Date(normalized);
  if (Number.isNaN(date.getTime())) return null;
  return date.getFullYear();
}

function inferRecordSeasonYear(record = {}, candidateValues = []) {
  const explicitYear = normalizeSeasonYearValue(record?.seasonYear, Number.NaN);
  if (Number.isFinite(explicitYear)) return explicitYear;
  for (const candidate of candidateValues) {
    const inferredYear = extractSeasonYearFromDateValue(candidate);
    if (inferredYear !== null) return inferredYear;
  }
  return currentSeasonYear();
}

function entityMediaSources(item = {}, entityType = "") {
  if (entityType === "category") {
    return [String(item?.image || "").trim()].filter(Boolean);
  }
  if (entityType === "card") {
    return normalizeVarietyImages(item);
  }
  if (entityType === "journal") {
    return [
      ...journalImages(item),
      String(item?.videoPath || "").trim(),
      String(item?.video || "").trim()
    ].filter(Boolean);
  }
  return [];
}

function hasPendingEntityMedia(item = {}, entityType = "") {
  return entityMediaSources(item, entityType).some((source) => isProcessableImageDataUrl(source));
}

function normalizeEntitySyncMeta(item = {}, entityType = "") {
  const dirty = Boolean(item?.dirty);
  const deleted = Boolean(item?.deleted);
  const syncUpdatedAtLocal = normalizeSyncTimestamp(item?.syncUpdatedAtLocal || item?.updatedAt || "");
  const lastSyncedAt = normalizeSyncTimestamp(item?.lastSyncedAt || "");
  let mediaSyncStatus = normalizeSyncMediaStatus(item?.mediaSyncStatus || "");
  if (hasPendingEntityMedia(item, entityType)) {
    if (mediaSyncStatus === "idle" || mediaSyncStatus === "done") {
      mediaSyncStatus = "pending";
    }
  } else if (mediaSyncStatus === "uploading") {
    mediaSyncStatus = "pending";
  } else if (!mediaSyncStatus) {
    mediaSyncStatus = "idle";
  }
  return {
    ...item,
    dirty,
    deleted,
    syncUpdatedAtLocal,
    lastSyncedAt,
    mediaSyncStatus
  };
}

function syncComparableRecord(item = {}) {
  if (!item || typeof item !== "object") return item;
  const next = { ...item };
  delete next.dirty;
  delete next.syncUpdatedAtLocal;
  delete next.lastSyncedAt;
  delete next.mediaSyncStatus;
  return next;
}

function recordsDifferForSync(currentRecord, previousRecord) {
  return JSON.stringify(syncComparableRecord(currentRecord)) !== JSON.stringify(syncComparableRecord(previousRecord));
}

function prepareCollectionForSyncPersistence(currentItems = [], previousItems = [], entityType = "", normalizer = (value) => value) {
  const previousById = new Map((Array.isArray(previousItems) ? previousItems : []).map((item) => [String(item?.id || "").trim(), item]));
  const changeTimestamp = new Date().toISOString();
  return (Array.isArray(currentItems) ? currentItems : []).map((item) => {
    const normalized = normalizer(item);
    const itemId = String(normalized?.id || "").trim();
    const previous = itemId ? previousById.get(itemId) || null : null;
    const pendingMedia = hasPendingEntityMedia(normalized, entityType);
    if (!previous) {
      return normalizeEntitySyncMeta({
        ...normalized,
        dirty: true,
        syncUpdatedAtLocal: normalizeSyncTimestamp(normalized?.syncUpdatedAtLocal) || changeTimestamp,
        mediaSyncStatus: pendingMedia ? "pending" : normalizeSyncMediaStatus(normalized?.mediaSyncStatus || "idle")
      }, entityType);
    }
    const normalizedPrevious = normalizer(previous);
    const changed = recordsDifferForSync(normalized, normalizedPrevious);
    const nextDirty = Boolean(normalized?.dirty) || changed;
    return normalizeEntitySyncMeta({
      ...normalized,
      dirty: nextDirty,
      syncUpdatedAtLocal: nextDirty
        ? (changed ? changeTimestamp : normalizeSyncTimestamp(normalized?.syncUpdatedAtLocal || normalizedPrevious?.syncUpdatedAtLocal || changeTimestamp))
        : normalizeSyncTimestamp(normalized?.syncUpdatedAtLocal || normalizedPrevious?.syncUpdatedAtLocal || ""),
      mediaSyncStatus: pendingMedia
        ? "pending"
        : normalizeSyncMediaStatus(normalized?.mediaSyncStatus || normalizedPrevious?.mediaSyncStatus || "idle")
    }, entityType);
  });
}

function prepareStateForSyncPersistence(currentState = {}, previousState = {}) {
  const previousVarieties = Array.isArray(previousState?.varieties) ? previousState.varieties.map(normalizeVarietyRecord) : [];
  const previousTasks = Array.isArray(previousState?.customTasks) ? previousState.customTasks.map((task) => normalizeTaskRecord(task, previousVarieties)) : [];
  const previousJournal = Array.isArray(previousState?.journal) ? previousState.journal.map((entry) => normalizeJournalEntry(entry, previousVarieties)) : [];
  const preparedCategories = prepareCollectionForSyncPersistence(
    sanitizeCategoryHierarchy(ensureRootCategories((Array.isArray(currentState?.categories) ? currentState.categories : []).map(normalizeCategoryRecord).map(applyDefaultParenting))),
    sanitizeCategoryHierarchy(ensureRootCategories((Array.isArray(previousState?.categories) ? previousState.categories : []).map(normalizeCategoryRecord).map(applyDefaultParenting))),
    "category",
    normalizeCategoryRecord
  );
  const preparedVarieties = prepareCollectionForSyncPersistence(
    Array.isArray(currentState?.varieties) ? currentState.varieties : [],
    previousVarieties,
    "card",
    normalizeVarietyRecord
  );
  const preparedTasks = prepareCollectionForSyncPersistence(
    Array.isArray(currentState?.customTasks) ? currentState.customTasks : [],
    previousTasks,
    "task",
    (task) => normalizeTaskRecord(task, preparedVarieties)
  );
  const preparedJournal = prepareCollectionForSyncPersistence(
    Array.isArray(currentState?.journal) ? currentState.journal : [],
    previousJournal,
    "journal",
    (entry) => normalizeJournalEntry(entry, preparedVarieties)
  );
  return {
    categories: enforceFixedCategoryNames(preparedCategories),
    varieties: preparedVarieties,
    customTasks: preparedTasks,
    journal: preparedJournal,
    autoTasks: Array.isArray(currentState?.autoTasks) ? currentState.autoTasks : []
  };
}

function localSyncRecordTimestamp(item = {}) {
  return normalizeSyncTimestamp(item?.syncUpdatedAtLocal || item?.updatedAt || item?.lastSyncedAt || "");
}

function touchLocalSyncRecord(item = {}, entityType = "", options = {}) {
  const timestamp = normalizeSyncTimestamp(options.timestamp || new Date().toISOString()) || new Date().toISOString();
  const nextDeleted = options.deleted === undefined ? Boolean(item?.deleted) : Boolean(options.deleted);
  const nextMediaStatus = options.mediaSyncStatus === undefined
    ? (hasPendingEntityMedia(item, entityType) ? "pending" : normalizeSyncMediaStatus(item?.mediaSyncStatus || "idle"))
    : normalizeSyncMediaStatus(options.mediaSyncStatus);
  return normalizeEntitySyncMeta({
    ...item,
    dirty: options.dirty === undefined ? true : Boolean(options.dirty),
    deleted: nextDeleted,
    syncUpdatedAtLocal: timestamp,
    mediaSyncStatus: nextMediaStatus
  }, entityType);
}

function clearLocalSyncDirty(item = {}, entityType = "", options = {}) {
  const syncedAt = normalizeSyncTimestamp(options.syncedAt || new Date().toISOString()) || new Date().toISOString();
  return normalizeEntitySyncMeta({
    ...item,
    dirty: false,
    lastSyncedAt: syncedAt,
    mediaSyncStatus: options.mediaSyncStatus === undefined
      ? item?.mediaSyncStatus
      : normalizeSyncMediaStatus(options.mediaSyncStatus)
  }, entityType);
}

function countPendingMediaForState(value = state) {
  const categories = Array.isArray(value?.categories) ? value.categories : [];
  const cards = Array.isArray(value?.varieties) ? value.varieties : [];
  const journal = Array.isArray(value?.journal) ? value.journal : [];
  return [
    ...categories.map((item) => ({ item: normalizeCategoryRecord(item), entityType: "category" })),
    ...cards.map((item) => ({ item: normalizeVarietyRecord(item), entityType: "card" })),
    ...journal.map((item) => ({ item: normalizeJournalEntry(item, cards), entityType: "journal" }))
  ].filter(({ item, entityType }) => {
    const mediaStatus = normalizeSyncMediaStatus(item?.mediaSyncStatus);
    if (mediaStatus === "uploading") return true;
    return hasPendingEntityMedia(item, entityType) && ["pending", "error", "uploading"].includes(mediaStatus);
  }).length;
}

function countDirtySyncRecords(value = state) {
  const categories = (Array.isArray(value?.categories) ? value.categories : []).map(normalizeCategoryRecord);
  const cards = (Array.isArray(value?.varieties) ? value.varieties : []).map(normalizeVarietyRecord);
  const tasks = (Array.isArray(value?.customTasks) ? value.customTasks : []).map((task) => normalizeTaskRecord(task, cards));
  const journal = (Array.isArray(value?.journal) ? value.journal : []).map((entry) => normalizeJournalEntry(entry, cards));
  return (
    syncRecordsPendingPush(categories, "category").length
    + syncRecordsPendingPush(cards, "card").length
    + syncRecordsPendingPush(tasks, "task").length
    + syncRecordsPendingPush(journal, "journal").length
  );
}

function softDeleteStateRecord(collectionKey = "", recordId = "", entityType = "", options = {}) {
  const normalizedRecordId = String(recordId || "").trim();
  if (!normalizedRecordId || !collectionKey) return false;
  const sourceCollection = Array.isArray(state?.[collectionKey]) ? state[collectionKey] : [];
  const existingRecord = sourceCollection.find((item) => String(item?.id || "").trim() === normalizedRecordId) || null;
  if (!existingRecord) return false;
  const previousUndoState = options?.previousUndoState === undefined
    ? snapshotUndoStateValue()
    : options.previousUndoState;
  if (entityType === "journal") {
    setUndoState({
      type: "journal",
      entry: clone(existingRecord)
    });
  } else if (entityType === "task") {
    setUndoState({
      type: "task",
      task: clone(existingRecord)
    });
  }
  let changed = false;
  state[collectionKey] = sourceCollection.map((item) => {
    if (String(item?.id || "").trim() !== normalizedRecordId) return item;
    changed = true;
    return touchLocalSyncRecord(item, entityType, { deleted: true });
  });
  return changed ? {
    changed: true,
    collectionKey,
    previousItems: sourceCollection.slice(),
    previousUndoState
  } : false;
}

function normalizeTaskRecord(task = {}, varieties = []) {
  const linkedVarietyId = String(task.linkedVarietyId || "").trim();
  const linkedCategoryIds = normalizeIdList(task.linkedCategoryIds?.length ? task.linkedCategoryIds : task.linkedCategoryId);
  let normalizedLinkedCategoryIds = linkedCategoryIds.slice();
  if (!normalizedLinkedCategoryIds.length && linkedVarietyId) {
    const inferredCategoryId = varieties.find((item) => item.id === linkedVarietyId)?.categoryId || "";
    normalizedLinkedCategoryIds = inferredCategoryId ? [inferredCategoryId] : [];
  }
  const linkedCategoryId = normalizedLinkedCategoryIds[0] || "";
  const seasonYear = inferRecordSeasonYear(task, [task.date]);
  return normalizeEntitySyncMeta({
    ...task,
    id: task.id || makeId("task"),
    text: String(task.text || "").trim(),
    date: String(task.date || "").trim(),
    done: Boolean(task.done),
    source: String(task.source || "").trim(),
    linkedCategoryIds: normalizedLinkedCategoryIds,
    linkedCategoryId,
    linkedVarietyId,
    seasonYear
  }, "task");
}

function normalizeTagList(value) {
  const items = Array.isArray(value)
    ? value
    : String(value || "")
      .split(",")
      .map((item) => item.trim());
  return [...new Set(items.filter(Boolean))];
}

function normalizeIdList(value) {
  const items = Array.isArray(value)
    ? value
    : [value];
  return [...new Set(items.map((item) => String(item || "").trim()).filter(Boolean))];
}

function normalizeWeatherSnapshot(value) {
  if (!value || typeof value !== "object") return null;
  const snapshot = {
    temperature: String(value.temperature || "").trim(),
    condition: String(value.condition || "").trim(),
    rain: String(value.rain || "").trim(),
    wind: String(value.wind || "").trim(),
    humidity: String(value.humidity || "").trim(),
    observedAt: String(value.observedAt || "").trim(),
    note: String(value.note || "").trim(),
    icon: String(value.icon || "").trim(),
    placeLabel: String(value.placeLabel || "").trim(),
    fetchedAt: String(value.fetchedAt || "").trim(),
    latitude: String(value.latitude || "").trim(),
    longitude: String(value.longitude || "").trim(),
    dayPeriod: String(value.dayPeriod || "").trim(),
    sunshineHours: Number.isFinite(Number(value.sunshineHours)) ? Number(value.sunshineHours) : null,
    moonPhase: String(value.moonPhase || "").trim(),
    isDay: Number.isFinite(Number(value.isDay)) ? Number(value.isDay) : null,
    temperatureC: Number.isFinite(Number(value.temperatureC)) ? Number(value.temperatureC) : null,
    apparentTemperatureC: Number.isFinite(Number(value.apparentTemperatureC)) ? Number(value.apparentTemperatureC) : null,
    humidityPct: Number.isFinite(Number(value.humidityPct)) ? Number(value.humidityPct) : null,
    precipitationMm: Number.isFinite(Number(value.precipitationMm)) ? Number(value.precipitationMm) : null,
    rainMm: Number.isFinite(Number(value.rainMm)) ? Number(value.rainMm) : null,
    showersMm: Number.isFinite(Number(value.showersMm)) ? Number(value.showersMm) : null,
    snowfallCm: Number.isFinite(Number(value.snowfallCm)) ? Number(value.snowfallCm) : null,
    cloudCoverPct: Number.isFinite(Number(value.cloudCoverPct)) ? Number(value.cloudCoverPct) : null,
    cloudCoverLowPct: Number.isFinite(Number(value.cloudCoverLowPct)) ? Number(value.cloudCoverLowPct) : null,
    cloudCoverMidPct: Number.isFinite(Number(value.cloudCoverMidPct)) ? Number(value.cloudCoverMidPct) : null,
    cloudCoverHighPct: Number.isFinite(Number(value.cloudCoverHighPct)) ? Number(value.cloudCoverHighPct) : null,
    windSpeedKmh: Number.isFinite(Number(value.windSpeedKmh)) ? Number(value.windSpeedKmh) : null,
    windGustsKmh: Number.isFinite(Number(value.windGustsKmh)) ? Number(value.windGustsKmh) : null,
    windDirectionDeg: Number.isFinite(Number(value.windDirectionDeg)) ? Number(value.windDirectionDeg) : null,
    visibilityM: Number.isFinite(Number(value.visibilityM)) ? Number(value.visibilityM) : null,
    pressureMslHpa: Number.isFinite(Number(value.pressureMslHpa)) ? Number(value.pressureMslHpa) : null,
    surfacePressureHpa: Number.isFinite(Number(value.surfacePressureHpa)) ? Number(value.surfacePressureHpa) : null,
    sunriseAt: String(value.sunriseAt || "").trim(),
    sunsetAt: String(value.sunsetAt || "").trim(),
    daylightSeconds: Number.isFinite(Number(value.daylightSeconds)) ? Number(value.daylightSeconds) : null,
    precipitationProbabilityPct: Number.isFinite(Number(value.precipitationProbabilityPct)) ? Number(value.precipitationProbabilityPct) : null
  };
  return Object.values(snapshot).some(Boolean) ? snapshot : null;
}

function normalizeWalkNumber(value) {
  const raw = String(value ?? "").trim();
  if (!raw) return null;
  const normalized = Number(raw.replace(",", "."));
  return Number.isFinite(normalized) ? normalized : null;
}

function normalizeWalkRoutePoints(value) {
  if (Array.isArray(value)) {
    return value
      .map((item) => {
        if (typeof item === "string") return item.trim();
        if (item && typeof item === "object") return String(item.label || item.name || item.title || "").trim();
        return "";
      })
      .filter(Boolean);
  }
  return String(value || "")
    .split(/\r?\n|,/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeWalkGpsPoints(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => {
      if (!item || typeof item !== "object") return null;
      const latitude = Number(item.latitude ?? item.lat);
      const longitude = Number(item.longitude ?? item.lng ?? item.lon);
      if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
      const recordedAt = String(item.recordedAt || item.timestamp || "").trim();
      const accuracyValue = normalizeWalkNumber(item.accuracyMeters ?? item.accuracy ?? item.accuracy_meters);
      return {
        latitude: Number(latitude.toFixed(6)),
        longitude: Number(longitude.toFixed(6)),
        recordedAt: recordedAt || new Date().toISOString(),
        accuracyMeters: accuracyValue !== null ? Math.max(0, Math.round(accuracyValue)) : null,
        source: String(item.source || "gps").trim() || "gps"
      };
    })
    .filter(Boolean);
}

function normalizeWalkPhotoStops(value) {
  if (!Array.isArray(value)) return [];
  return value
    .map((item) => {
      if (!item || typeof item !== "object") return null;
      const latitude = Number(item.latitude ?? item.lat);
      const longitude = Number(item.longitude ?? item.lng ?? item.lon);
      if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
      return {
        latitude: Number(latitude.toFixed(6)),
        longitude: Number(longitude.toFixed(6)),
        recordedAt: String(item.recordedAt || item.capturedAt || "").trim() || new Date().toISOString(),
        imageIndex: Number.isFinite(Number(item.imageIndex)) ? Number(item.imageIndex) : 0
      };
    })
    .filter(Boolean);
}

function nearestWalkGpsPoint(points = [], recordedAt = "") {
  if (!Array.isArray(points) || !points.length) return null;
  const targetTime = Date.parse(String(recordedAt || "").trim());
  if (!Number.isFinite(targetTime)) return points[points.length - 1] || null;
  let bestPoint = points[0] || null;
  let bestDiff = Number.POSITIVE_INFINITY;
  points.forEach((point) => {
    const pointTime = Date.parse(point?.recordedAt || "");
    if (!Number.isFinite(pointTime)) return;
    const diff = Math.abs(pointTime - targetTime);
    if (diff < bestDiff) {
      bestDiff = diff;
      bestPoint = point;
    }
  });
  return bestPoint || points[points.length - 1] || null;
}

function buildWalkPhotoStop(point, imageIndex = 0, recordedAt = "") {
  if (!point || !Number.isFinite(Number(point.latitude)) || !Number.isFinite(Number(point.longitude))) return null;
  return {
    latitude: Number(point.latitude),
    longitude: Number(point.longitude),
    recordedAt: String(recordedAt || point.recordedAt || new Date().toISOString()).trim() || new Date().toISOString(),
    imageIndex: Number.isFinite(Number(imageIndex)) ? Number(imageIndex) : 0
  };
}

const WALK_GPS_DISPLAY_INITIAL_MAX_ACCEPTED_ACCURACY_METERS = 45;
const WALK_GPS_DISPLAY_MAX_ACCEPTED_ACCURACY_METERS = 80;
const WALK_GPS_DISPLAY_MIN_CLEARANCE_METERS = 12;
const WALK_GPS_DISPLAY_MAX_WALKING_SPEED_KMH = 12;

function sanitizeWalkGpsPointsForDisplay(points = []) {
  const normalizedPoints = normalizeWalkGpsPoints(points);
  if (!normalizedPoints.length) return [];
  const filteredPoints = [];
  normalizedPoints.forEach((point) => {
    const accuracyMeters = Number(point?.accuracyMeters);
    if (Number.isFinite(accuracyMeters) && accuracyMeters > WALK_GPS_DISPLAY_MAX_ACCEPTED_ACCURACY_METERS) {
      return;
    }
    if (!filteredPoints.length) {
      if (Number.isFinite(accuracyMeters) && accuracyMeters > WALK_GPS_DISPLAY_INITIAL_MAX_ACCEPTED_ACCURACY_METERS) {
        return;
      }
      filteredPoints.push(point);
      return;
    }
    const previousPoint = filteredPoints[filteredPoints.length - 1] || null;
    if (!previousPoint) {
      filteredPoints.push(point);
      return;
    }
    const distanceKm = walkGpsDistanceKm([previousPoint, point]) || 0;
    const distanceMeters = distanceKm * 1000;
    const previousTime = Date.parse(previousPoint.recordedAt || "");
    const nextTime = Date.parse(point.recordedAt || "");
    const secondsDiff = Number.isFinite(previousTime) && Number.isFinite(nextTime)
      ? Math.abs(nextTime - previousTime) / 1000
      : Number.POSITIVE_INFINITY;
    if (distanceMeters <= WALK_GPS_DISPLAY_MIN_CLEARANCE_METERS && secondsDiff < 20) {
      return;
    }
    if (Number.isFinite(secondsDiff) && secondsDiff > 0) {
      const speedKmh = distanceKm / (secondsDiff / 3600);
      if (speedKmh > WALK_GPS_DISPLAY_MAX_WALKING_SPEED_KMH) {
        return;
      }
    }
    filteredPoints.push(point);
  });
  return filteredPoints.length ? filteredPoints : normalizedPoints;
}

function resolveWalkPhotoRecordedAtForFile(file, points = []) {
  const normalizedPoints = normalizeWalkGpsPoints(points);
  const fallbackRecordedAt = String(normalizedPoints[normalizedPoints.length - 1]?.recordedAt || new Date().toISOString()).trim() || new Date().toISOString();
  const fileStamp = Number(file?.lastModified || 0);
  if (!Number.isFinite(fileStamp) || fileStamp <= 0 || normalizedPoints.length < 2) {
    return fallbackRecordedAt;
  }
  const firstPointTime = Date.parse(normalizedPoints[0]?.recordedAt || "");
  const lastPointTime = Date.parse(normalizedPoints[normalizedPoints.length - 1]?.recordedAt || "");
  if (!Number.isFinite(firstPointTime) || !Number.isFinite(lastPointTime)) {
    return new Date(fileStamp).toISOString();
  }
  const paddedStart = firstPointTime - (30 * 60 * 1000);
  const paddedEnd = lastPointTime + (30 * 60 * 1000);
  if (fileStamp < paddedStart || fileStamp > paddedEnd) {
    return fallbackRecordedAt;
  }
  return new Date(fileStamp).toISOString();
}

function buildWalkPhotoStopsForSubmission({
  gpsPoints = [],
  existingPhotoStops = [],
  existingImageCount = 0,
  pendingFiles = []
} = {}) {
  const normalizedPoints = sanitizeWalkGpsPointsForDisplay(gpsPoints);
  const preservedStops = normalizeWalkPhotoStops(existingPhotoStops)
    .filter((item) => Number.isFinite(Number(item?.imageIndex)) && Number(item.imageIndex) < Math.max(0, Number(existingImageCount) || 0));
  if (!normalizedPoints.length || !Array.isArray(pendingFiles) || !pendingFiles.length) {
    return preservedStops;
  }
  const nextStops = pendingFiles
    .map((file, pendingIndex) => {
      const imageIndex = Math.max(0, Number(existingImageCount) || 0) + pendingIndex;
      const recordedAt = resolveWalkPhotoRecordedAtForFile(file, normalizedPoints);
      const nearestPoint = nearestWalkGpsPoint(normalizedPoints, recordedAt) || normalizedPoints[normalizedPoints.length - 1] || null;
      return buildWalkPhotoStop(nearestPoint, imageIndex, recordedAt);
    })
    .filter(Boolean);
  return [...preservedStops, ...nextStops];
}

function walkGpsDistanceKm(points = []) {
  if (!Array.isArray(points) || points.length < 2) return null;
  const originalKey = `walk-distance:${walkGpsPointsCacheKey(points)}`;
  const cacheKey = `${currentCacheVersion()}_${originalKey}`;
  try {
    const cached = getCachedValue(__cache.derived, cacheKey);
    if (cached !== CACHE_MISS) {
      debugCacheHit("walk-distance", cacheKey);
      return cached;
    }
  } catch (error) {
    // Cache helper nesmie zastaviť výpočet.
  }
  const toRadians = (value) => (value * Math.PI) / 180;
  let totalDistance = 0;
  for (let index = 1; index < points.length; index += 1) {
    const previous = points[index - 1];
    const current = points[index];
    const latitudeDelta = toRadians(current.latitude - previous.latitude);
    const longitudeDelta = toRadians(current.longitude - previous.longitude);
    const startLatitude = toRadians(previous.latitude);
    const endLatitude = toRadians(current.latitude);
    const haversine = Math.sin(latitudeDelta / 2) ** 2
      + Math.cos(startLatitude) * Math.cos(endLatitude) * Math.sin(longitudeDelta / 2) ** 2;
    const arc = 2 * Math.atan2(Math.sqrt(haversine), Math.sqrt(1 - haversine));
    totalDistance += 6371 * arc;
  }
  const result = totalDistance > 0 ? Number(totalDistance.toFixed(3)) : null;
  try {
    setCache(__cache.derived, cacheKey, result);
  } catch (error) {
    // Cache helper nesmie zastaviť výpočet.
  }
  return result;
}

function walkDurationMinutesFromBounds(startedAt = "", endedAt = "", { live = false, pausedDurationMs = 0 } = {}) {
  const start = Date.parse(String(startedAt || "").trim());
  const end = endedAt
    ? Date.parse(String(endedAt || "").trim())
    : (live ? Date.now() : Number.NaN);
  if (!Number.isFinite(start) || !Number.isFinite(end) || end < start) return null;
  const pausedMs = Math.max(0, Number(pausedDurationMs) || 0);
  return Math.max(0, Math.round((end - start - pausedMs) / 60000));
}

function walkGpsDurationMinutes(points = [], startedAt = "", endedAt = "", options = {}) {
  const originalKey = JSON.stringify({
    kind: "walk-duration",
    points: walkGpsPointsCacheKey(points),
    startedAt: String(startedAt || "").trim(),
    endedAt: String(endedAt || "").trim(),
    live: Boolean(options?.live),
    pausedDurationMs: Math.max(0, Number(options?.pausedDurationMs) || 0)
  });
  const cacheKey = `${currentCacheVersion()}_${originalKey}`;
  try {
    const cached = getCachedValue(__cache.derived, cacheKey);
    if (cached !== CACHE_MISS) {
      debugCacheHit("walk-duration", cacheKey);
      return cached;
    }
  } catch (error) {
    // Cache helper nesmie zastaviť výpočet.
  }
  const boundedDuration = walkDurationMinutesFromBounds(startedAt, endedAt, options);
  if (boundedDuration !== null) {
    try {
      setCache(__cache.derived, cacheKey, boundedDuration);
    } catch (error) {
      // Cache helper nesmie zastaviť výpočet.
    }
    return boundedDuration;
  }
  if (!Array.isArray(points) || points.length < 2) {
    try {
      setCache(__cache.derived, cacheKey, null);
    } catch (error) {
      // Cache helper nesmie zastaviť výpočet.
    }
    return null;
  }
  const start = Date.parse(points[0]?.recordedAt || "");
  const end = Date.parse(points[points.length - 1]?.recordedAt || "");
  if (!Number.isFinite(start) || !Number.isFinite(end) || end < start) {
    try {
      setCache(__cache.derived, cacheKey, null);
    } catch (error) {
      // Cache helper nesmie zastaviť výpočet.
    }
    return null;
  }
  const result = Math.max(0, Math.round((end - start) / 60000));
  try {
    setCache(__cache.derived, cacheKey, result);
  } catch (error) {
    // Cache helper nesmie zastaviť výpočet.
  }
  return result;
}

function formatWalkDateTime(value = "") {
  const timestamp = Date.parse(String(value || "").trim());
  if (!Number.isFinite(timestamp)) return "";
  return new Date(timestamp).toLocaleTimeString("sk-SK", { hour: "2-digit", minute: "2-digit" });
}

function walkAutoTitle(walkValue, fallbackDate = todayISO()) {
  const walk = normalizeJournalWalk({ walk: walkValue }) || null;
  const startedAt = String(walk?.startedAt || "").trim();
  const startTimestamp = Date.parse(startedAt);
  if (Number.isFinite(startTimestamp)) {
    const dateLabel = new Date(startTimestamp).toLocaleDateString("sk-SK", { day: "numeric", month: "numeric" });
    const timeLabel = new Date(startTimestamp).toLocaleTimeString("sk-SK", { hour: "2-digit", minute: "2-digit" });
    return `Prechádzka ${dateLabel} • ${timeLabel}`;
  }
  const dateValue = String(fallbackDate || todayISO()).trim() || todayISO();
  return `Prechádzka ${formatDate(dateValue)}`;
}

function walkTimeRangeLabel(walkValue) {
  const walk = normalizeJournalWalk({ walk: walkValue }) || null;
  if (!walk) return "";
  const gpsPoints = Array.isArray(walk.gpsPoints) ? walk.gpsPoints : [];
  const startedAt = String(walk.startedAt || gpsPoints[0]?.recordedAt || "").trim();
  const endedAt = String(walk.endedAt || gpsPoints[gpsPoints.length - 1]?.recordedAt || "").trim();
  const startTime = formatWalkDateTime(startedAt);
  const endTime = formatWalkDateTime(endedAt);
  if (startTime && endTime) return `${startTime} - ${endTime}`;
  return startTime || endTime || "";
}

function formatWalkGpsCoordinates(point) {
  if (!point || !Number.isFinite(Number(point.latitude)) || !Number.isFinite(Number(point.longitude))) return "";
  return `${Number(point.latitude).toFixed(5)}, ${Number(point.longitude).toFixed(5)}`;
}

function formatWalkGpsPointLabel(point, index = 0, total = 0) {
  const dateValue = Date.parse(point?.recordedAt || "");
  const timeLabel = Number.isFinite(dateValue)
    ? new Date(dateValue).toLocaleTimeString("sk-SK", { hour: "2-digit", minute: "2-digit" })
    : "";
  const accuracyLabel = Number.isFinite(Number(point?.accuracyMeters)) ? `±${Math.round(Number(point.accuracyMeters))} m` : "";
  const label = index === 0
    ? "Štart"
    : (total && index === total - 1 ? "Koniec" : `Bod ${index + 1}`);
  return [label, timeLabel, accuracyLabel].filter(Boolean).join(" • ");
}

function formatWalkGpsPlaceLabel(point, kind = "point") {
  return "";
}

function displayWalkPlaceLabel(value = "") {
  const normalized = String(value || "").trim();
  if (!normalized) return "";
  const withoutCoordinates = normalized
    .replace(/\s*[•\-–]\s*-?\d+(?:\.\d+)?\s*,\s*-?\d+(?:\.\d+)?/gu, "")
    .replace(/\s{2,}/g, " ")
    .trim();
  if (withoutCoordinates.includes("Štart GPS")) return "Štart GPS";
  if (withoutCoordinates.includes("Koniec GPS")) return "Koniec GPS";
  if (withoutCoordinates.includes("GPS bod")) return "GPS bod";
  return withoutCoordinates;
}

function journalDisplayTitle(entry = {}) {
  const normalizedEntry = entry && typeof entry === "object" ? entry : {};
  const fallbackTitle = String(normalizedEntry.title || "Zápis").trim() || "Zápis";
  if (normalizedEntry.entryType !== "walk") return fallbackTitle;
  if (/^prechádzka\b/iu.test(fallbackTitle)) {
    return "Prechádzka";
  }
  return fallbackTitle;
}

function journalPreviewTitleInfo(entry = {}, maxLength = 72) {
  const normalizedEntry = entry && typeof entry === "object" ? entry : {};
  const displayTitle = String(journalDisplayTitle(normalizedEntry) || "").trim();
  const typeLabel = String(journalEntryTypeLabel(normalizedEntry.entryType || JOURNAL_ENTRY_TYPES.NOTE) || "Zápis").trim();
  const noteTitle = trimText(String(normalizedEntry.text || "").replace(/\s+/g, " ").trim(), maxLength);
  const normalizedDisplayTitle = displayTitle.toLocaleLowerCase("sk-SK");
  const normalizedTypeLabel = typeLabel.toLocaleLowerCase("sk-SK");
  const shouldUseNoteTitle = Boolean(noteTitle) && (!normalizedDisplayTitle || normalizedDisplayTitle === normalizedTypeLabel);

  return {
    title: shouldUseNoteTitle ? noteTitle : (displayTitle || typeLabel || "Zápis"),
    usesNoteTitle: shouldUseNoteTitle
  };
}

function journalHeaderWeather(entry = {}) {
  const normalizedEntry = entry && typeof entry === "object" ? entry : {};
  const directWeather = normalizeWeatherSnapshot(normalizedEntry.weather);
  if (directWeather) return directWeather;
  const walk = normalizeJournalWalk({ walk: normalizedEntry.walk || normalizedEntry }, directWeather);
  if (!walk) return null;
  return normalizeWeatherSnapshot({
    temperature: walk.temperature,
    condition: walk.conditions,
    rain: walk.precipitation,
    wind: walk.wind
  });
}

function markAppBootReady() {
  if (typeof document === "undefined") return;
  const root = document.documentElement;
  const hadStartupMask = root.classList.contains("app-startup-stable")
    || root.classList.contains("app-startup-mobile-shell");
  if (typeof window !== "undefined" && typeof window.requestAnimationFrame === "function") {
    window.requestAnimationFrame(() => {
      root.classList.remove("app-startup-stable");
      root.classList.remove("app-startup-mobile-shell");
      if (hadStartupMask) {
        syncMobileTopStripVisibility();
      }
    });
    return;
  }
  root.classList.remove("app-startup-stable");
  root.classList.remove("app-startup-mobile-shell");
  if (hadStartupMask) {
    syncMobileTopStripVisibility();
  }
}

function isCloudSignedInForHomeExperience() {
  const authMirror = loadSupabaseAuthMirror();
  return Boolean(String(authMirror?.email || "").trim());
}

function shouldUseCleanLoggedOutHome() {
  return !isFocusedView && !isCloudSignedInForHomeExperience();
}

function syncLoggedOutHomeExperience() {
  if (typeof document === "undefined") return;
  const useCleanHome = shouldUseCleanLoggedOutHome();
  document.body.classList.toggle("app-clean-logged-out-home", useCleanHome);
  if (worklogPanelToggleEl) {
    worklogPanelToggleEl.hidden = useCleanHome;
    if (useCleanHome) {
      worklogPanelToggleEl.style.setProperty("display", "none", "important");
    } else {
      worklogPanelToggleEl.style.removeProperty("display");
    }
  }
}

function installBootRefreshMask() {
  if (typeof window === "undefined") return;
  if (window.__mojaZahradaBootRefreshMaskInstalled) return;
  window.__mojaZahradaBootRefreshMaskInstalled = true;
}

function ensureLeafletLoaded() {
  if (typeof document === "undefined" || typeof window === "undefined") {
    return Promise.resolve(null);
  }
  if (window.L) return Promise.resolve(window.L);
  if (leafletRuntimeLoadPromise) return leafletRuntimeLoadPromise;

  const ensureCss = () => {
    if (document.head?.querySelector('link[data-runtime-leaflet="true"]')) return;
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = LEAFLET_CSS_URL;
    link.crossOrigin = "";
    link.integrity = LEAFLET_CSS_INTEGRITY;
    link.setAttribute("data-runtime-leaflet", "true");
    document.head?.appendChild(link);
  };

  leafletRuntimeLoadPromise = new Promise((resolve, reject) => {
    ensureCss();
    const existingScript = document.querySelector('script[data-runtime-leaflet="true"]');
    if (existingScript) {
      existingScript.addEventListener("load", () => resolve(window.L || null), { once: true });
      existingScript.addEventListener("error", reject, { once: true });
      return;
    }

    const script = document.createElement("script");
    script.src = LEAFLET_JS_URL;
    script.crossOrigin = "";
    script.integrity = LEAFLET_JS_INTEGRITY;
    script.defer = true;
    script.setAttribute("data-runtime-leaflet", "true");
    script.addEventListener("load", () => resolve(window.L || null), { once: true });
    script.addEventListener("error", () => {
      leafletRuntimeLoadPromise = null;
      reject(new Error("Leaflet sa teraz nepodarilo načítať."));
    }, { once: true });
    document.head?.appendChild(script);
  }).catch((error) => {
    console.warn("Mapa sa teraz nepodarila pripraviť.", error);
    return null;
  });

  return leafletRuntimeLoadPromise;
}

function walkMapPoints(walkValue) {
  const walk = normalizeJournalWalk({ walk: walkValue }) || null;
  return Array.isArray(walk?.gpsPoints) ? walk.gpsPoints.filter((point) => Number.isFinite(point.latitude) && Number.isFinite(point.longitude)) : [];
}

function renderWalkMapDeferredShellMarkup(points = [], { compact = false, live = false, photoCount = 0 } = {}) {
  const safePoints = Array.isArray(points) ? points.filter((point) => Number.isFinite(point?.latitude) && Number.isFinite(point?.longitude)) : [];
  if (!safePoints.length) return "";
  return `
    <button class="journal-walk__map-launch" type="button" data-walk-map-activate>
      <span class="journal-walk__map-launch-icon" aria-hidden="true">${ICONS.walkGps}</span>
      <span class="journal-walk__map-launch-copy">
        <strong>Zobraziť mapu prechádzky</strong>
        <span>${escapeHtml(countedLabel(safePoints.length, "GPS bod", "GPS body", "GPS bodov"))}</span>
      </span>
    </button>
  `;
}

function renderWalkMapInnerMarkup(points = [], { compact = false, live = false, photoCount = 0, photoEntryId = "", collapsible = false } = {}) {
  const safePoints = Array.isArray(points) ? points.filter((point) => Number.isFinite(point?.latitude) && Number.isFinite(point?.longitude)) : [];
  if (!safePoints.length) return "";
  return `
    <div
      class="journal-walk__map ${compact ? "journal-walk__map--compact" : ""} ${live ? "journal-walk__map--live" : ""}"
      data-walk-map
      data-walk-map-photo-count="${escapeAttribute(String(Math.max(0, Number(photoCount) || 0)))}"
      data-walk-map-photo-entry="${escapeAttribute(String(photoEntryId || "").trim())}"
      data-walk-map-points="${escapeAttribute(JSON.stringify(safePoints.map((point) => ({
        latitude: point.latitude,
        longitude: point.longitude
      }))))}"
    ></div>
    ${compact && collapsible ? `
      <button class="journal-walk__map-collapse" type="button" data-walk-map-collapse aria-label="Skryť mapu" title="Skryť mapu">Skryť mapu</button>
    ` : ""}
    ${compact ? "" : `
      <button class="journal-walk__map-expand" type="button" data-walk-map-fullscreen aria-label="Celá mapa" title="Celá mapa">
        <svg viewBox="0 0 24 24" aria-hidden="true">
          <path d="M8 4H4v4"></path>
          <path d="M16 4h4v4"></path>
          <path d="M20 16v4h-4"></path>
          <path d="M4 16v4h4"></path>
        </svg>
      </button>
    `}
  `;
}

function renderWalkMapMarkup(walkValue, { compact = false, live = false, photoCount = 0, photoEntryId = "", deferred = false } = {}) {
  const points = walkMapPoints(walkValue);
  if (points.length < 1) return "";
  const encodedPoints = escapeAttribute(JSON.stringify(points.map((point) => ({
    latitude: point.latitude,
    longitude: point.longitude
  }))));
  const encodedPhotoCount = escapeAttribute(String(Math.max(0, Number(photoCount) || 0)));
  const encodedPhotoEntryId = escapeAttribute(String(photoEntryId || "").trim());

  if (deferred) {
    return `
      <div
        class="journal-walk__map-shell journal-walk__map-shell--deferred ${compact ? "journal-walk__map-shell--compact" : ""} ${live ? "journal-walk__map-shell--live" : ""}"
        data-walk-map-shell
        data-walk-map-points="${encodedPoints}"
        data-walk-map-photo-count="${encodedPhotoCount}"
        data-walk-map-photo-entry="${encodedPhotoEntryId}"
      >
        ${renderWalkMapDeferredShellMarkup(points, { compact, live, photoCount })}
      </div>
    `;
  }

  return `
    <div
      class="journal-walk__map-shell ${compact ? "journal-walk__map-shell--compact" : ""} ${live ? "journal-walk__map-shell--live" : ""}"
      data-walk-map-shell
      data-walk-map-points="${encodedPoints}"
      data-walk-map-photo-count="${encodedPhotoCount}"
      data-walk-map-photo-entry="${encodedPhotoEntryId}"
    >
      ${renderWalkMapInnerMarkup(points, { compact, live, photoCount, photoEntryId })}
    </div>
  `;
}

function hydrateWalkMaps(root = document) {
  if (!root || typeof root.querySelectorAll !== "function" || typeof window === "undefined") return;
  const mapElements = [...root.querySelectorAll("[data-walk-map]")];
  if (!mapElements.length) return;
  if (!window.L) {
    ensureLeafletLoaded().then((leaflet) => {
      if (!leaflet) return;
      hydrateWalkMaps(root);
    }).catch(() => {});
    return;
  }
  mapElements.forEach((mapEl) => {
    if (mapEl.dataset.walkMapReady === "true") return;
    const normalizedPoints = walkMapPointsFromElement(mapEl);
    const photoCount = Math.max(0, Number(mapEl.getAttribute("data-walk-map-photo-count") || 0) || 0);
    const photoEntryId = walkMapPhotoEntryIdFromElement(mapEl);
    const photoImages = walkMapPhotoImagesForEntry(photoEntryId);
    const photoLabel = walkMapPhotoLabelForEntry(photoEntryId);
    if (normalizedPoints.length < 1) return;

    const map = window.L.map(mapEl, {
      zoomControl: true,
      attributionControl: true,
      dragging: true,
      scrollWheelZoom: true,
      doubleClickZoom: true,
      boxZoom: false,
      keyboard: false,
      zoomAnimation: false,
      fadeAnimation: false,
      markerZoomAnimation: false,
      tap: true,
      touchZoom: true
    });

    createWalkTileLayer(map, mapEl);
    walkMapInstances.set(mapEl, map);
    attachWalkMapControls(mapEl, () => walkMapInstances.get(mapEl));

    const startPoint = normalizedPoints[0];
    const endPoint = normalizedPoints[normalizedPoints.length - 1];

    let polyline = null;
    if (normalizedPoints.length >= 2) {
      polyline = window.L.polyline(
        normalizedPoints.map((point) => [Number(point.latitude), Number(point.longitude)]),
        {
          color: "#6f963d",
          weight: mapEl.classList.contains("journal-walk__map--compact") ? 4 : 5,
          opacity: 0.92,
          lineCap: "round",
          lineJoin: "round"
        }
      ).addTo(map);
    }

    window.L.circleMarker([Number(startPoint.latitude), Number(startPoint.longitude)], {
      radius: 6,
      color: "#3f6a2a",
      weight: 2,
      fillColor: "#f5fff0",
      fillOpacity: 1
    }).addTo(map);

    window.L.circleMarker([Number(endPoint.latitude), Number(endPoint.longitude)], {
      radius: 6,
      color: "#9c5b2b",
      weight: 2,
      fillColor: "#fff3e8",
      fillOpacity: 1
    }).addTo(map);

    walkMapPhotoMarkerPoints(normalizedPoints, photoImages, photoCount).forEach((markerEntry) => {
      const point = markerEntry?.point || null;
      const photoIndex = Math.max(0, Number(markerEntry?.photoIndex) || 0);
      const photoSource = String(markerEntry?.photoSource || "").trim();
      const duplicateIndex = Math.max(0, Number(markerEntry?.duplicateIndex) || 0);
      const duplicateCount = Math.max(1, Number(markerEntry?.duplicateCount) || 1);
      if (!point) return;
      const markerPoint = offsetWalkPhotoMarkerPoint(point, duplicateIndex, duplicateCount);
      const marker = window.L.marker([Number(markerPoint.latitude), Number(markerPoint.longitude)], {
        keyboard: false,
        zIndexOffset: 600,
        icon: window.L.divIcon({
          className: "journal-walk__photo-marker",
          html: `<span style="display:grid;place-items:center;width:22px;height:22px;border-radius:999px;background:rgba(255,251,244,0.98);border:1px solid rgba(186,155,90,0.42);box-shadow:0 6px 14px rgba(52,41,25,0.16);font-size:11px;font-weight:800;line-height:1;color:#6d5329;">${escapeHtml(String(photoIndex + 1))}</span>`,
          iconSize: [22, 22],
          iconAnchor: [11, 11]
        }),
        title: photoCount > 1 ? `Fotka ${photoIndex + 1}` : "Fotka"
      }).addTo(map);
      if (!photoSource) return;
      marker.bindPopup(renderWalkMapPhotoPopupMarkup(photoSource, photoIndex), {
        className: "journal-walk__photo-popup-shell",
        closeButton: false,
        offset: [0, -12],
        maxWidth: 160
      });
      marker.on("popupopen", () => {
        const popupEl = marker.getPopup()?.getElement();
        const openButton = popupEl?.querySelector?.("[data-walk-map-photo-open]");
        if (!(openButton instanceof HTMLButtonElement) || openButton.dataset.walkMapPhotoBound === "true") return;
        openButton.dataset.walkMapPhotoBound = "true";
        openButton.addEventListener("click", () => {
          openImageLightbox(photoImages, photoIndex, photoLabel || "Fotka");
        });
      });
    });

    fitWalkMapViewport(map, {
      polyline,
      point: startPoint,
      compact: mapEl.classList.contains("journal-walk__map--compact"),
      live: mapEl.classList.contains("journal-walk__map--live"),
      points: normalizedPoints
    });
    scheduleWalkMapResize(map);
    mapEl.dataset.walkMapReady = "true";
  });
}

function walkRoutePointsText(walk) {
  const normalizedWalk = normalizeJournalWalk({ walk }) || null;
  return normalizedWalk?.routePoints?.join("\n") || "";
}

function normalizeJournalWalk(entry = {}, fallbackWeather = null) {
  const hasWalkObject = entry?.walk && typeof entry.walk === "object";
  const hasLegacyWalkShape = [
    "startPlace",
    "start",
    "endPlace",
    "end",
    "distanceKm",
    "distance",
    "durationMinutes",
    "duration",
    "routePoints",
    "routePointsText",
    "route"
  ].some((key) => Object.prototype.hasOwnProperty.call(entry || {}, key));
  const source = hasWalkObject
    ? entry.walk
    : hasLegacyWalkShape
      ? entry
      : null;
  if (!source || typeof source !== "object") return null;

  const weather = fallbackWeather && typeof fallbackWeather === "object" ? fallbackWeather : null;
  const originalKey = JSON.stringify({
    id: String(entry?.id || "").trim(),
    updatedAt: normalizeSyncTimestamp(entry?.syncUpdatedAtLocal || entry?.updatedAt || entry?.lastSyncedAt || ""),
    source: walkSourceCacheKey(source),
    weather: walkWeatherCacheKey(weather)
  });
  const cacheKey = `${currentCacheVersion()}_${originalKey}`;
  try {
    const cached = getCachedValue(__cache.walks, cacheKey);
    if (cached !== CACHE_MISS) {
      debugCacheHit("walk-normalize", cacheKey);
      return cached;
    }
  } catch (error) {
    // Cache helper nesmie zastaviť normalizáciu.
  }
  const normalized = {
    startPlace: String(source.startPlace || source.start || "").trim(),
    endPlace: String(source.endPlace || source.end || "").trim(),
    startedAt: String(source.startedAt || source.started_at || "").trim(),
    endedAt: String(source.endedAt || source.ended_at || "").trim(),
    pausedAt: String(source.pausedAt || source.paused_at || "").trim(),
    pausedDurationMs: Math.max(0, Number(source.pausedDurationMs || source.paused_duration_ms || 0) || 0),
    distanceKm: normalizeWalkNumber(source.distanceKm ?? source.distance),
    durationMinutes: normalizeWalkNumber(source.durationMinutes ?? source.durationMinutes ?? source.duration),
    routePoints: normalizeWalkRoutePoints(source.routePoints?.length ? source.routePoints : (source.routePointsText || source.route || "")),
    gpsPoints: normalizeWalkGpsPoints(source.gpsPoints),
    temperature: String(source.temperature || "").trim(),
    wind: String(source.wind || "").trim(),
    precipitation: String(source.precipitation || source.rain || "").trim(),
    conditions: String(source.conditions || source.condition || "").trim()
  };

  if (normalized.distanceKm === null) {
    const gpsDistance = walkGpsDistanceKm(normalized.gpsPoints);
    if (gpsDistance !== null) normalized.distanceKm = gpsDistance;
  }
  if (normalized.durationMinutes === null) {
    const gpsDuration = walkGpsDurationMinutes(normalized.gpsPoints, normalized.startedAt, normalized.endedAt, {
      pausedDurationMs: normalized.pausedDurationMs
    });
    if (gpsDuration !== null) normalized.durationMinutes = gpsDuration;
  }

  if (!normalized.temperature && weather?.temperature) normalized.temperature = String(weather.temperature).trim();
  if (!normalized.wind && weather?.wind) normalized.wind = String(weather.wind).trim();
  if (!normalized.precipitation && weather?.rain) normalized.precipitation = String(weather.rain).trim();
  if (!normalized.conditions && weather?.condition) normalized.conditions = String(weather.condition).trim();

  const hasContent = Boolean(
    normalized.startPlace
    || normalized.endPlace
    || normalized.startedAt
    || normalized.endedAt
    || normalized.pausedAt
    || normalized.pausedDurationMs
    || normalized.distanceKm !== null
    || normalized.durationMinutes !== null
    || normalized.routePoints.length
    || normalized.gpsPoints.length
    || normalized.temperature
    || normalized.wind
    || normalized.precipitation
    || normalized.conditions
  );

  const result = hasContent ? normalized : null;
  try {
    setCache(__cache.walks, cacheKey, result);
  } catch (error) {
    // Cache helper nesmie zastaviť normalizáciu.
  }
  return result;
}

// Shared helpers for module wiring and error reporting.
function logModuleError(scope, error, extra) {
  const normalizedScope = String(scope || "module").trim() || "module";
  if (typeof extra === "undefined") {
    console.error(`[MojaZahrada][${normalizedScope}]`, error);
    return;
  }
  console.error(`[MojaZahrada][${normalizedScope}]`, error, extra);
}

