function categoryCardImage(category) {
  if (category.image) return category.image;
  const restored = restoreSeedCategoryImage(category);
  if (restored) return restored;
  return categoryPlaceholderImage(category);
}

function shouldDeferCategoryCardImageSource(source = "") {
  const normalized = String(source || "").trim();
  if (!shouldUseMobileDeferredVarietyImages() || !normalized || isPlaceholderImage(normalized)) return false;
  if (isRealMobileRuntimeMode()) return true;
  return isProcessableImageDataUrl(normalized) && normalized.length > 18000;
}

function renderCategoryCardImageTag(category, altText) {
  const source = categoryCardImage(category);
  const hasDirectSource = isDirectRenderableImageSource(source);
  const hasResolvableStoragePath = Boolean(extractSupabaseStoragePath(source));
  const shouldDeferSource = shouldDeferCategoryCardImageSource(source);
  const needsResolvedSource = !hasDirectSource;
  if (!needsResolvedSource && !hasResolvableStoragePath && !shouldDeferSource) {
    return `<img src="${escapeAttribute(source)}" alt="${escapeAttribute(altText)}" loading="lazy" decoding="async" fetchpriority="low">`;
  }
  const cachedPreviewSource = getCachedPreviewImageSource(source, LIST_IMAGE_PREVIEW_MAX_DIMENSION);
  if (!needsResolvedSource && cachedPreviewSource && cachedPreviewSource !== source) {
    return `<img src="${escapeAttribute(cachedPreviewSource)}" alt="${escapeAttribute(altText)}" loading="lazy" decoding="async" fetchpriority="low">`;
  }
  const optimisticSource = hasDirectSource && !shouldDeferSource
    ? source
    : categoryPlaceholderImage(category);
  return `<img src="${escapeAttribute(optimisticSource)}" data-lazy-category-image="${escapeAttribute(category.id)}" alt="${escapeAttribute(altText)}" loading="lazy" decoding="async" fetchpriority="low">`;
}

function resolveDeferredCategoryCardImageSource(categoryId = "") {
  const normalizedId = String(categoryId || "").trim();
  if (!normalizedId) return "";
  const category = state.categories.find((item) => item.id === normalizedId);
  return category ? categoryCardImage(category) : "";
}

function getCachedPreviewImageSource(source = "", maxDimension = LIST_IMAGE_PREVIEW_MAX_DIMENSION) {
  const normalized = String(source || "").trim();
  if (!shouldDerivePreviewImageSource(normalized)) return normalized;
  const safeMaxDimension = Math.max(160, Number(maxDimension) || LIST_IMAGE_PREVIEW_MAX_DIMENSION);
  const cacheKey = `${safeMaxDimension}|${normalized}`;
  return derivedPreviewImageCache.get(cacheKey) || "";
}

async function activateDeferredCategoryCardImage(img) {
  if (!(img instanceof HTMLImageElement)) return;
  if (img.dataset.deferredCardActivationPending === "true") return;
  img.dataset.deferredCardActivationPending = "true";
  try {
    const categoryId = String(img.getAttribute("data-lazy-category-image") || "").trim();
    if (!categoryId) return;
    const source = resolveDeferredCategoryCardImageSource(categoryId);
    if (!source) return;
    const renderableSource = await resolveRenderableSupabaseImageSource(source);
    if (!isDirectRenderableImageSource(renderableSource)) return;
    const previewSource = await resolvePreviewImageSource(renderableSource, LIST_IMAGE_PREVIEW_MAX_DIMENSION);
    if (!img.isConnected) return;
    img.src = previewSource || renderableSource;
    img.removeAttribute("data-lazy-category-image");
    if (deferredCategoryCardImageObserver) {
      try {
        deferredCategoryCardImageObserver.unobserve(img);
      } catch (error) {
        // Ignore stale observer detach errors.
      }
    }
  } finally {
    img.removeAttribute("data-deferred-card-activation-queued");
    img.removeAttribute("data-deferred-card-activation-pending");
  }
}

function syncDeferredCategoryCardImages(root = document) {
  if (typeof window === "undefined") return;
  const pendingImages = [...root.querySelectorAll("img[data-lazy-category-image]")];
  if (!pendingImages.length) return;

  const immediateCount = Math.max(0, Math.min(pendingImages.length, isRealMobileRuntimeMode() ? 4 : 0));
  if (immediateCount > 0) {
    pendingImages.slice(0, immediateCount).forEach((img) => activateDeferredCategoryCardImage(img));
  }

  const remainingImages = pendingImages.filter((img) => img.hasAttribute("data-lazy-category-image"));
  if (!remainingImages.length) return;

  if ("IntersectionObserver" in window) {
    if (!deferredCategoryCardImageObserver) {
      deferredCategoryCardImageObserver = new IntersectionObserver((entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          scheduleDeferredCardImageActivation(entry.target, activateDeferredCategoryCardImage);
        });
      }, {
        root: null,
        rootMargin: deferredCardImageRootMargin(),
        threshold: 0.01
      });
    }
    remainingImages.forEach((img) => deferredCategoryCardImageObserver.observe(img));
    return;
  }

  remainingImages.forEach((img) => scheduleDeferredCardImageActivation(img, activateDeferredCategoryCardImage));
}

function shouldDeferJournalImageSource(source = "") {
  const normalized = String(source || "").trim();
  if (!shouldUseMobileDeferredVarietyImages() || !normalized || isPlaceholderImage(normalized)) return false;
  if (isRealMobileRuntimeMode()) return true;
  return isProcessableImageDataUrl(normalized) && normalized.length > 18000;
}

function deferredJournalImageRootMargin() {
  if (isRealMobileRuntimeMode()) return "96px 0px";
  return deferredCardImageRootMargin();
}

function renderJournalImageTag(source, altText, { entryId = "", index = 0, className = "", style = "", previewVariant = "", forceDeferred = false } = {}) {
  const normalizedSource = String(source || "").trim();
  if (!normalizedSource) return "";
  const classAttribute = className ? ` class="${escapeAttribute(className)}"` : "";
  const styleAttribute = style ? ` style="${escapeAttribute(style)}"` : "";
  const previewVariantAttribute = previewVariant ? ` data-journal-preview-variant="${escapeAttribute(previewVariant)}"` : "";
  const requiresResolution = !isDirectRenderableImageSource(normalizedSource);
  const shouldDefer = forceDeferred
    ? shouldUseMobileDeferredVarietyImages() && !isPlaceholderImage(normalizedSource)
    : (requiresResolution || shouldDeferJournalImageSource(normalizedSource));
  if (!shouldDefer) {
    return `<img src="${escapeAttribute(normalizedSource)}" alt="${escapeAttribute(altText)}" loading="lazy" decoding="async" fetchpriority="low"${previewVariantAttribute}${classAttribute}${styleAttribute}>`;
  }
  return `<img src="${escapeAttribute(placeholderImage())}" data-lazy-journal-image-entry="${escapeAttribute(entryId)}" data-lazy-journal-image-index="${escapeAttribute(String(index))}" alt="${escapeAttribute(altText)}" loading="lazy" decoding="async" fetchpriority="low"${previewVariantAttribute}${classAttribute}${styleAttribute}>`;
}

function resolveDeferredJournalImageSource(entryId = "", imageIndex = 0) {
  const normalizedEntryId = String(entryId || "").trim();
  if (!normalizedEntryId) return "";
  const entry = state.journal.find((item) => String(item?.id || "").trim() === normalizedEntryId);
  if (!entry) return "";
  const images = journalImages(entry);
  if (!images.length) return "";
  const normalizedIndex = Math.max(0, Number(imageIndex) || 0);
  return images[normalizedIndex] || images[0] || "";
}

async function activateDeferredJournalImage(img) {
  if (!(img instanceof HTMLImageElement)) return;
  const entryId = String(img.getAttribute("data-lazy-journal-image-entry") || "").trim();
  if (!entryId) return;
  const imageIndex = Math.max(0, Number(img.getAttribute("data-lazy-journal-image-index") || 0) || 0);
  const source = resolveDeferredJournalImageSource(entryId, imageIndex);
  if (!source) return;
  const renderableSource = await resolveRenderableSupabaseImageSource(source);
  if (!isDirectRenderableImageSource(renderableSource)) return;
  const previewVariant = String(img.getAttribute("data-journal-preview-variant") || "").trim();
  const previewSource = previewVariant === "sidebar-media"
    ? await resolveJournalSidebarPreviewImageSource(renderableSource, JOURNAL_LIST_IMAGE_PREVIEW_MAX_DIMENSION)
    : await resolvePreviewImageSource(renderableSource, JOURNAL_LIST_IMAGE_PREVIEW_MAX_DIMENSION);
  if (!img.isConnected) return;
  img.src = previewSource || renderableSource;
  img.removeAttribute("data-lazy-journal-image-entry");
  img.removeAttribute("data-lazy-journal-image-index");
  if (deferredJournalImageObserver) {
    try {
      deferredJournalImageObserver.unobserve(img);
    } catch (error) {
      // Ignore stale observer detach errors.
    }
  }
}

function syncDeferredJournalImages(root = document, { eagerCount = 0 } = {}) {
  if (!shouldUseMobileDeferredVarietyImages()) return;
  const pendingImages = [...root.querySelectorAll("img[data-lazy-journal-image-entry]")];
  if (!pendingImages.length) return;

  const immediateCount = Math.max(
    0,
    Math.min(
      pendingImages.length,
      Number.isFinite(Number(eagerCount))
        ? Number(eagerCount)
        : (isRealMobileRuntimeMode() ? 2 : 0)
    )
  );

  if (immediateCount > 0) {
    pendingImages.slice(0, immediateCount).forEach((img) => activateDeferredJournalImage(img));
  }

  const remainingImages = pendingImages.filter((img) => img.hasAttribute("data-lazy-journal-image-entry"));
  if (!remainingImages.length) return;

  if ("IntersectionObserver" in window) {
    if (!deferredJournalImageObserver) {
      deferredJournalImageObserver = new IntersectionObserver((entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          activateDeferredJournalImage(entry.target);
        });
      }, {
        root: null,
        rootMargin: deferredJournalImageRootMargin(),
        threshold: 0.01
      });
    }
    remainingImages.forEach((img) => deferredJournalImageObserver.observe(img));
    return;
  }

  remainingImages.forEach((img) => activateDeferredJournalImage(img));
}

function fileToDataUrl(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function isProcessableImageDataUrl(value) {
  return typeof value === "string"
    && value.startsWith("data:image/")
    && !value.startsWith("data:image/svg+xml");
}

function imageMimeTypeFromDataUrl(value = "") {
  const match = String(value || "").match(/^data:(image\/[a-z0-9.+-]+);/i);
  return match ? String(match[1] || "").trim().toLowerCase() : "";
}

function shouldApplyWhiteEdgeCleanupForMime(mimeType = "") {
  const normalized = String(mimeType || "").trim().toLowerCase();
  // Agresívne vybielenie okrajov robilo mapy na fotkách v protisvetle,
  // preto ho nechávame len pre PNG vstupy, kde ešte môže pomôcť s bielym pozadím.
  return normalized === "image/png";
}

function shouldDerivePreviewImageSource(source = "") {
  const normalized = String(source || "").trim();
  return isProcessableImageDataUrl(normalized) && normalized.length > 18000;
}

async function resolvePreviewImageSource(source = "", maxDimension = LIST_IMAGE_PREVIEW_MAX_DIMENSION, quality = 0.72) {
  const normalized = String(source || "").trim();
  if (!shouldDerivePreviewImageSource(normalized)) return normalized;

  const safeMaxDimension = Math.max(160, Number(maxDimension) || LIST_IMAGE_PREVIEW_MAX_DIMENSION);
  const cacheKey = `${safeMaxDimension}|${normalized}`;
  if (derivedPreviewImageCache.has(cacheKey)) {
    return derivedPreviewImageCache.get(cacheKey);
  }
  if (derivedPreviewImagePromiseCache.has(cacheKey)) {
    return derivedPreviewImagePromiseCache.get(cacheKey);
  }

  const promise = new Promise((resolve) => {
    const image = new Image();
    image.decoding = "async";
    image.onload = () => {
      try {
        const scale = Math.min(1, safeMaxDimension / Math.max(image.width || 1, image.height || 1));
        const width = Math.max(1, Math.round((image.width || 1) * scale));
        const height = Math.max(1, Math.round((image.height || 1) * scale));
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const context = canvas.getContext("2d");
        if (!context) {
          resolve(normalized);
          return;
        }
        context.drawImage(image, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", quality));
      } catch (error) {
        resolve(normalized);
      }
    };
    image.onerror = () => resolve(normalized);
    image.src = normalized;
  }).then((resolved) => {
    derivedPreviewImagePromiseCache.delete(cacheKey);
    derivedPreviewImageCache.set(cacheKey, resolved);
    if (derivedPreviewImageCache.size > 160) {
      const oldestKey = derivedPreviewImageCache.keys().next().value;
      if (oldestKey) derivedPreviewImageCache.delete(oldestKey);
    }
    return resolved;
  });

  derivedPreviewImagePromiseCache.set(cacheKey, promise);
  return promise;
}

function hasVisibleContentInRow(data, width, y) {
  const minVisiblePixels = Math.max(2, Math.round(width * 0.04));
  let visiblePixels = 0;
  const rowOffset = y * width * 4;
  for (let x = 0; x < width; x += 1) {
    if (!isLightBackgroundPixel(data, rowOffset + x * 4) && ++visiblePixels >= minVisiblePixels) {
      return true;
    }
  }
  return false;
}

function hasVisibleContentInColumn(data, width, height, x) {
  const minVisiblePixels = Math.max(2, Math.round(height * 0.04));
  let visiblePixels = 0;
  for (let y = 0; y < height; y += 1) {
    if (!isLightBackgroundPixel(data, (y * width + x) * 4) && ++visiblePixels >= minVisiblePixels) {
      return true;
    }
  }
  return false;
}

function detectLightTrimBounds(canvas) {
  const context = canvas.getContext("2d");
  if (!context) return null;

  const width = canvas.width;
  const height = canvas.height;
  if (width < 8 || height < 8) return null;

  const imageData = context.getImageData(0, 0, width, height);
  const { data } = imageData;
  let top = 0;
  let bottom = height - 1;
  let left = 0;
  let right = width - 1;

  while (top < bottom && !hasVisibleContentInRow(data, width, top)) top += 1;
  while (bottom > top && !hasVisibleContentInRow(data, width, bottom)) bottom -= 1;
  while (left < right && !hasVisibleContentInColumn(data, width, height, left)) left += 1;
  while (right > left && !hasVisibleContentInColumn(data, width, height, right)) right -= 1;

  const trimmedWidth = right - left + 1;
  const trimmedHeight = bottom - top + 1;
  if (trimmedWidth < 8 || trimmedHeight < 8) return null;

  const widthReduction = width - trimmedWidth;
  const heightReduction = height - trimmedHeight;
  if (widthReduction < Math.round(width * 0.06) && heightReduction < Math.round(height * 0.06)) {
    return null;
  }

  return {
    x: left,
    y: top,
    width: trimmedWidth,
    height: trimmedHeight
  };
}

function fitCropRectToAspect(rect, targetAspectRatio, imageWidth, imageHeight) {
  let x = Math.max(0, Number(rect?.x) || 0);
  let y = Math.max(0, Number(rect?.y) || 0);
  let width = Math.max(1, Number(rect?.width) || imageWidth || 1);
  let height = Math.max(1, Number(rect?.height) || imageHeight || 1);
  const currentAspectRatio = width / Math.max(1, height);

  if (currentAspectRatio > targetAspectRatio) {
    const targetWidth = Math.max(1, Math.round(height * targetAspectRatio));
    x += Math.max(0, Math.round((width - targetWidth) / 2));
    width = targetWidth;
  } else if (currentAspectRatio < targetAspectRatio) {
    const targetHeight = Math.max(1, Math.round(width / targetAspectRatio));
    y += Math.max(0, Math.round((height - targetHeight) / 2));
    height = targetHeight;
  }

  if (x + width > imageWidth) x = Math.max(0, imageWidth - width);
  if (y + height > imageHeight) y = Math.max(0, imageHeight - height);

  return { x, y, width, height };
}

function zoomCropRect(rect, keepRatio, imageWidth, imageHeight, focusX = 0.5, focusY = 0.5) {
  const safeKeepRatio = Math.min(1, Math.max(0.18, Number(keepRatio) || 1));
  const width = Math.max(1, Math.round((Number(rect?.width) || imageWidth || 1) * safeKeepRatio));
  const height = Math.max(1, Math.round((Number(rect?.height) || imageHeight || 1) * safeKeepRatio));
  const rectX = Math.max(0, Number(rect?.x) || 0);
  const rectY = Math.max(0, Number(rect?.y) || 0);
  const rectWidth = Math.max(1, Number(rect?.width) || imageWidth || 1);
  const rectHeight = Math.max(1, Number(rect?.height) || imageHeight || 1);
  const centerX = rectX + rectWidth * Math.min(1, Math.max(0, Number(focusX) || 0.5));
  const centerY = rectY + rectHeight * Math.min(1, Math.max(0, Number(focusY) || 0.5));
  let x = Math.round(centerX - width * Math.min(1, Math.max(0, Number(focusX) || 0.5)));
  let y = Math.round(centerY - height * Math.min(1, Math.max(0, Number(focusY) || 0.5)));

  if (x + width > imageWidth) x = Math.max(0, imageWidth - width);
  if (y + height > imageHeight) y = Math.max(0, imageHeight - height);

  return { x, y, width, height };
}

function scorePreviewCropRect(data, imageWidth, rect, leftBiasWeight = 0) {
  const width = Math.max(1, Math.round(Number(rect?.width) || 1));
  const height = Math.max(1, Math.round(Number(rect?.height) || 1));
  const startX = Math.max(0, Math.round(Number(rect?.x) || 0));
  const startY = Math.max(0, Math.round(Number(rect?.y) || 0));
  const step = Math.max(2, Math.round(Math.min(width, height) / 18));
  let totalSamples = 0;
  let contentSamples = 0;

  for (let y = startY; y < startY + height; y += step) {
    for (let x = startX; x < startX + width; x += step) {
      totalSamples += 1;
      if (!isLightBackgroundPixel(data, (y * imageWidth + x) * 4)) {
        contentSamples += 1;
      }
    }
  }

  const densityScore = totalSamples ? contentSamples / totalSamples : 0;
  const leftBiasScore = 1 - (startX / Math.max(1, imageWidth - width));
  return densityScore + leftBiasScore * leftBiasWeight;
}

function findContentAwarePreviewCrop(canvas, bounds, targetAspectRatio) {
  const context = canvas.getContext("2d");
  if (!context) {
    return fitCropRectToAspect(bounds, targetAspectRatio, canvas.width, canvas.height);
  }

  const imageWidth = canvas.width;
  const imageHeight = canvas.height;
  const baseRect = fitCropRectToAspect(bounds, targetAspectRatio, imageWidth, imageHeight);
  const { data } = context.getImageData(0, 0, imageWidth, imageHeight);
  const portraitLike = bounds.height > bounds.width * 1.08;
  const keepRatios = portraitLike ? [0.5, 0.62, 0.74, 0.86] : [0.74, 0.86, 1];
  const horizontalSteps = portraitLike ? 5 : 4;
  const verticalSteps = portraitLike ? 6 : 4;
  let bestRect = baseRect;
  let bestScore = -Infinity;

  keepRatios.forEach((keepRatio) => {
    const candidateSize = zoomCropRect(baseRect, keepRatio, imageWidth, imageHeight, 0.5, portraitLike ? 0.34 : 0.5);
    const maxX = Math.max(bounds.x, bounds.x + bounds.width - candidateSize.width);
    const maxY = Math.max(bounds.y, bounds.y + bounds.height - candidateSize.height);

    for (let xIndex = 0; xIndex <= horizontalSteps; xIndex += 1) {
      const xRatio = horizontalSteps === 0 ? 0 : xIndex / horizontalSteps;
      const x = Math.round(bounds.x + (maxX - bounds.x) * xRatio);
      for (let yIndex = 0; yIndex <= verticalSteps; yIndex += 1) {
        const yRatio = verticalSteps === 0 ? 0 : yIndex / verticalSteps;
        const y = Math.round(bounds.y + (maxY - bounds.y) * yRatio);
        const rect = {
          x,
          y,
          width: candidateSize.width,
          height: candidateSize.height
        };
        const score = scorePreviewCropRect(data, imageWidth, rect, portraitLike ? 0.12 : 0.04) + keepRatio * 0.08;
        if (score > bestScore) {
          bestScore = score;
          bestRect = rect;
        }
      }
    }
  });

  return bestRect;
}

async function resolveJournalSidebarPreviewImageSource(source = "", maxDimension = JOURNAL_LIST_IMAGE_PREVIEW_MAX_DIMENSION, quality = 0.76) {
  const normalized = String(source || "").trim();
  if (!normalized || isPlaceholderImage(normalized)) return normalized;

  const safeMaxDimension = Math.max(160, Number(maxDimension) || JOURNAL_LIST_IMAGE_PREVIEW_MAX_DIMENSION);
  const cacheKey = `journal-sidebar-v7|${safeMaxDimension}|${normalized}`;
  if (derivedPreviewImageCache.has(cacheKey)) {
    return derivedPreviewImageCache.get(cacheKey);
  }
  if (derivedPreviewImagePromiseCache.has(cacheKey)) {
    return derivedPreviewImagePromiseCache.get(cacheKey);
  }

  const promise = new Promise((resolve) => {
    const image = new Image();
    image.decoding = "async";
    if (/^https?:/i.test(normalized)) {
      image.crossOrigin = "anonymous";
    }
    image.onload = () => {
      try {
        const sourceCanvas = document.createElement("canvas");
        sourceCanvas.width = Math.max(1, image.width || 1);
        sourceCanvas.height = Math.max(1, image.height || 1);
        const sourceContext = sourceCanvas.getContext("2d");
        if (!sourceContext) {
          resolve(normalized);
          return;
        }

        sourceContext.drawImage(image, 0, 0, sourceCanvas.width, sourceCanvas.height);
        const trimmedBounds = detectLightTrimBounds(sourceCanvas) || {
          x: 0,
          y: 0,
          width: sourceCanvas.width,
          height: sourceCanvas.height
        };
        const cropRect = findContentAwarePreviewCrop(
          sourceCanvas,
          trimmedBounds,
          JOURNAL_SIDEBAR_MEDIA_ASPECT_RATIO
        );
        const scale = Math.min(1, safeMaxDimension / Math.max(cropRect.width || 1, cropRect.height || 1));
        const outputWidth = Math.max(1, Math.round((cropRect.width || 1) * scale));
        const outputHeight = Math.max(1, Math.round((cropRect.height || 1) * scale));
        const outputCanvas = document.createElement("canvas");
        outputCanvas.width = outputWidth;
        outputCanvas.height = outputHeight;
        const outputContext = outputCanvas.getContext("2d");
        if (!outputContext) {
          resolve(normalized);
          return;
        }

        outputContext.drawImage(
          image,
          cropRect.x,
          cropRect.y,
          cropRect.width,
          cropRect.height,
          0,
          0,
          outputWidth,
          outputHeight
        );
        resolve(outputCanvas.toDataURL("image/jpeg", quality));
      } catch (error) {
        resolve(normalized);
      }
    };
    image.onerror = () => resolve(normalized);
    image.src = normalized;
  }).then((resolved) => {
    derivedPreviewImagePromiseCache.delete(cacheKey);
    derivedPreviewImageCache.set(cacheKey, resolved);
    if (derivedPreviewImageCache.size > 160) {
      const oldestKey = derivedPreviewImageCache.keys().next().value;
      if (oldestKey) derivedPreviewImageCache.delete(oldestKey);
    }
    return resolved;
  });

  derivedPreviewImagePromiseCache.set(cacheKey, promise);
  return promise;
}

function isLightBackgroundPixel(data, index) {
  const alpha = data[index + 3];
  if (alpha < 16) return true;

  const red = data[index];
  const green = data[index + 1];
  const blue = data[index + 2];
  const max = Math.max(red, green, blue);
  const min = Math.min(red, green, blue);
  const spread = max - min;
  const luminance = 0.2126 * red + 0.7152 * green + 0.0722 * blue;

  return luminance >= 205 && spread <= 85;
}

function whitenEdgeBackgroundOnCanvas(canvas) {
  const context = canvas.getContext("2d");
  if (!context) return false;

  const width = canvas.width;
  const height = canvas.height;
  const imageData = context.getImageData(0, 0, width, height);
  const { data } = imageData;
  const visited = new Uint8Array(width * height);
  const queue = [];
  let changed = false;

  const enqueue = (x, y) => {
    if (x < 0 || y < 0 || x >= width || y >= height) return;
    const offset = y * width + x;
    if (visited[offset]) return;
    const pixelIndex = offset * 4;
    if (!isLightBackgroundPixel(data, pixelIndex)) return;
    visited[offset] = 1;
    queue.push(offset);
  };

  for (let x = 0; x < width; x += 1) {
    enqueue(x, 0);
    enqueue(x, height - 1);
  }

  for (let y = 0; y < height; y += 1) {
    enqueue(0, y);
    enqueue(width - 1, y);
  }

  while (queue.length) {
    const offset = queue.pop();
    const pixelIndex = offset * 4;
    if (data[pixelIndex] !== 255 || data[pixelIndex + 1] !== 255 || data[pixelIndex + 2] !== 255 || data[pixelIndex + 3] !== 255) {
      data[pixelIndex] = 255;
      data[pixelIndex + 1] = 255;
      data[pixelIndex + 2] = 255;
      data[pixelIndex + 3] = 255;
      changed = true;
    }

    const x = offset % width;
    const y = Math.floor(offset / width);
    enqueue(x - 1, y);
    enqueue(x + 1, y);
    enqueue(x, y - 1);
    enqueue(x, y + 1);
  }

  if (changed) {
    context.putImageData(imageData, 0, 0);
  }

  return changed;
}

function normalizeImageBackgroundDataUrl(dataUrl) {
  return new Promise((resolve) => {
    if (!isProcessableImageDataUrl(dataUrl)) {
      resolve(dataUrl);
      return;
    }
    const sourceMimeType = imageMimeTypeFromDataUrl(dataUrl);
    if (!shouldApplyWhiteEdgeCleanupForMime(sourceMimeType)) {
      resolve(dataUrl);
      return;
    }

    const image = new Image();
    image.onload = () => {
      const canvas = document.createElement("canvas");
      canvas.width = image.width;
      canvas.height = image.height;
      const context = canvas.getContext("2d");
      if (!context) {
        resolve(dataUrl);
        return;
      }

      context.fillStyle = "#ffffff";
      context.fillRect(0, 0, canvas.width, canvas.height);
      context.imageSmoothingEnabled = true;
      context.imageSmoothingQuality = "high";
      context.drawImage(image, 0, 0);
      const changed = whitenEdgeBackgroundOnCanvas(canvas);
      resolve(changed ? canvas.toDataURL("image/jpeg", 0.92) : dataUrl);
    };
    image.onerror = () => resolve(dataUrl);
    image.src = dataUrl;
  });
}

function fileToOptimizedDataUrl(file, maxDimension = 1200, quality = 0.92) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const image = new Image();
      image.onload = () => {
        const sourceMimeType = String(file?.type || "").trim().toLowerCase() || imageMimeTypeFromDataUrl(String(reader.result || ""));
        const scale = Math.min(1, maxDimension / Math.max(image.width, image.height));
        const width = Math.max(1, Math.round(image.width * scale));
        const height = Math.max(1, Math.round(image.height * scale));
        const canvas = document.createElement("canvas");
        canvas.width = width;
        canvas.height = height;
        const context = canvas.getContext("2d");
        if (!context) {
          resolve(reader.result);
          return;
        }
        context.fillStyle = "#ffffff";
        context.fillRect(0, 0, width, height);
        context.imageSmoothingEnabled = true;
        context.imageSmoothingQuality = "high";
        context.drawImage(image, 0, 0, width, height);
        if (shouldApplyWhiteEdgeCleanupForMime(sourceMimeType)) {
          whitenEdgeBackgroundOnCanvas(canvas);
        }
        resolve(canvas.toDataURL("image/jpeg", quality));
      };
      image.onerror = () => resolve(reader.result);
      image.src = reader.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function scheduleImageBackgroundCleanup() {
  if (imageBackgroundCleanupScheduled) return;
  if (localStorage.getItem(IMAGE_BACKGROUND_MIGRATION_KEY) === "done") return;

  imageBackgroundCleanupScheduled = true;
  window.setTimeout(async () => {
    let changed = false;
    const cache = new Map();

    const normalizeSource = async (source) => {
      if (!isProcessableImageDataUrl(source)) return source;
      if (!cache.has(source)) {
        cache.set(source, normalizeImageBackgroundDataUrl(source));
      }
      return cache.get(source);
    };

    for (const category of state.categories) {
      const cleaned = await normalizeSource(category.image || "");
      if (cleaned !== category.image) {
        category.image = cleaned;
        changed = true;
      }
    }

    for (const variety of state.varieties) {
      const currentImages = normalizeVarietyImages(variety);
      const cleanedImages = [];
      let varietyChanged = false;

      for (const image of currentImages) {
        const cleaned = await normalizeSource(image);
        cleanedImages.push(cleaned);
        if (cleaned !== image) varietyChanged = true;
      }

      if (varietyChanged) {
        variety.images = cleanedImages;
        variety.image = cleanedImages[0] || placeholderImage();
        changed = true;
      }
    }

    if (!changed) {
      localStorage.setItem(IMAGE_BACKGROUND_MIGRATION_KEY, "done");
      imageBackgroundCleanupScheduled = false;
      return;
    }

    if (!persist()) {
      imageBackgroundCleanupScheduled = false;
      return;
    }

    localStorage.setItem(IMAGE_BACKGROUND_MIGRATION_KEY, "done");
    imageBackgroundCleanupScheduled = false;
    render();
  }, 0);
}

function syncFilterButtons() {
  document.querySelectorAll(".filter").forEach((item) => item.classList.remove("is-active"));
  const button = document.querySelector(`.filter[data-filter="${activeFilter}"]`);
  if (button) button.classList.add("is-active");
  if (activeFilterLabelEl) activeFilterLabelEl.textContent = filterLabel(activeFilter);
}

function filterLabel(filter) {
  const labels = {
    all: "Všetko",
    sown: "Vysiate",
    favorite: "Top odrody",
    avoid: "Nechcem ďalší rok"
  };
  return labels[filter] || labels.all;
}

function clone(value) {
  return JSON.parse(JSON.stringify(value));
}

function makeId(prefix) {
  return `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
}

function percent(part, total) {
  if (!total) return 0;
  return Math.max(0, Math.min(100, Math.round((part / total) * 100)));
}

function setUndoState(payload) {
  lastDeleted = payload;
  localStorage.setItem(UNDO_KEY, JSON.stringify(payload));
  updateUndoButton();
}

function loadUndoState() {
  try {
    const raw = localStorage.getItem(UNDO_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch (error) {
    return null;
  }
}

function saveResetBackup() {
  const snapshot = arguments.length > 0 ? arguments[0] : serializeStateSnapshot();
  const reason = String(arguments.length > 1 ? arguments[1] : "manual").trim() || "manual";
  try {
    localStorage.setItem(RESET_BACKUP_KEY, JSON.stringify({
      savedAt: new Date().toISOString(),
      reason,
      state: snapshot
    }));
    updateRestoreResetButton();
    return true;
  } catch (error) {
    return false;
  }
}

function loadResetBackup() {
  try {
    const raw = localStorage.getItem(RESET_BACKUP_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || !parsed.state || typeof parsed.state !== "object") {
      return null;
    }
    return {
      savedAt: String(parsed.savedAt || "").trim(),
      reason: String(parsed.reason || "").trim(),
      state: normalizePersistedState(parsed.state)
    };
  } catch (error) {
    return null;
  }
}

function updateRestoreResetButton() {
  if (!restoreResetEl) return;
  const backup = loadResetBackup();
  restoreResetEl.hidden = !backup;
  restoreResetEl.disabled = !backup;
  if (!backup) {
    restoreResetEl.textContent = "Obnoviť poistnú zálohu";
    restoreResetEl.title = "";
    return;
  }
  const savedLabel = backup.savedAt ? formatDate(backup.savedAt) : "";
  restoreResetEl.textContent = savedLabel
    ? `Obnoviť poistnú zálohu (${savedLabel})`
    : "Obnoviť poistnú zálohu";
  restoreResetEl.title = savedLabel
    ? `Posledná poistná záloha: ${savedLabel}`
    : "Obnoviť poslednú poistnú zálohu";
}

function restoreResetBackup() {
  const backup = loadResetBackup();
  if (!backup?.state) {
    throw new Error("V tejto appke teraz nevidím žiadnu uloženú poistnú zálohu.");
  }

  const previousState = serializeStateSnapshot();
  const previousActiveCategoryId = activeCategoryId;
  state = normalizePersistedState(backup.state);
  clearAppCache();
  invalidateDerivedDataCaches();
  if (!state.categories.some((item) => item.id === activeCategoryId)) {
    activeCategoryId = firstActiveCategoryId(state.categories);
  }

  if (!persist({ skipAutoSync: true })) {
    state = normalizePersistedState(previousState);
    clearAppCache();
    invalidateDerivedDataCaches();
    activeCategoryId = previousActiveCategoryId;
    persist({ skipAutoSync: true });
    throw new Error("Poistná záloha sa načítala, ale nepodarilo sa ju bezpečne uložiť späť do appky.");
  }

  render();
  showAppToast("Poistná záloha obnovená", { tone: "success" });
  return {
    savedAt: backup.savedAt,
    reason: backup.reason,
    varieties: activeSyncCount(state.varieties),
    tasks: activeSyncCount(state.customTasks),
    journal: activeSyncCount(state.journal)
  };
}

function clearUndoState() {
  lastDeleted = null;
  localStorage.removeItem(UNDO_KEY);
  updateUndoButton();
}

function undoLastDelete() {
  if (!lastDeleted) return;
  const undoSnapshot = clone(lastDeleted);
  const previousState = serializeStateSnapshot();
  const previousActiveCategoryId = activeCategoryId;

  if (undoSnapshot.type === "category" && undoSnapshot.category) {
    const deletedCategories = Array.isArray(undoSnapshot.categories) && undoSnapshot.categories.length
      ? undoSnapshot.categories
      : [undoSnapshot.category];
    deletedCategories.forEach((item) => {
      const existingCategoryIndex = state.categories.findIndex((entry) => entry.id === item.id);
      if (existingCategoryIndex >= 0) {
        state.categories[existingCategoryIndex] = clone(item);
        return;
      }
      state.categories.push(clone(item));
    });

    (undoSnapshot.varieties || []).forEach((item) => {
      const existingVarietyIndex = state.varieties.findIndex((entry) => entry.id === item.id);
      if (existingVarietyIndex >= 0) {
        state.varieties[existingVarietyIndex] = clone(item);
        return;
      }
      state.varieties.push(clone(item));
    });

    (undoSnapshot.movedCategories || []).forEach((item) => {
      const existingCategoryIndex = state.categories.findIndex((entry) => entry.id === item.id);
      if (existingCategoryIndex >= 0) {
        state.categories[existingCategoryIndex] = clone(item);
        return;
      }
      state.categories.push(clone(item));
    });

    (undoSnapshot.customTasks || []).forEach((item) => {
      const existingTaskIndex = state.customTasks.findIndex((entry) => entry.id === item.id);
      if (existingTaskIndex >= 0) {
        state.customTasks[existingTaskIndex] = clone(item);
        return;
      }
      state.customTasks.push(clone(item));
    });

    (undoSnapshot.journal || []).forEach((item) => {
      const existingJournalIndex = state.journal.findIndex((entry) => entry.id === item.id);
      if (existingJournalIndex >= 0) {
        state.journal[existingJournalIndex] = clone(item);
        return;
      }
      state.journal.push(clone(item));
    });

    activeCategoryId = deletedCategories[0]?.id || undoSnapshot.previousActiveCategoryId || undoSnapshot.category.id;
  }

  if (undoSnapshot.type === "variety" && undoSnapshot.variety) {
    const existingVarietyIndex = state.varieties.findIndex((item) => item.id === undoSnapshot.variety.id);
    if (existingVarietyIndex >= 0) {
      state.varieties[existingVarietyIndex] = clone(undoSnapshot.variety);
    } else {
      state.varieties.push(clone(undoSnapshot.variety));
    }
    activeCategoryId = undoSnapshot.variety.categoryId;
  }

  if (undoSnapshot.type === "journal" && undoSnapshot.entry) {
    const restoredEntry = touchLocalSyncRecord(clone(undoSnapshot.entry), "journal", { deleted: false });
    const existingJournalIndex = state.journal.findIndex((item) => item.id === restoredEntry.id);
    if (existingJournalIndex >= 0) {
      state.journal[existingJournalIndex] = restoredEntry;
    } else {
      state.journal.unshift(restoredEntry);
    }
  }

  if (undoSnapshot.type === "task" && undoSnapshot.task) {
    const restoredTask = touchLocalSyncRecord(clone(undoSnapshot.task), "task", { deleted: false });
    const existingTaskIndex = state.customTasks.findIndex((item) => item.id === restoredTask.id);
    if (existingTaskIndex >= 0) {
      state.customTasks[existingTaskIndex] = restoredTask;
    } else {
      state.customTasks.unshift(restoredTask);
    }
  }

  refreshAutoTasks();
  if (!persist()) {
    state = normalizePersistedState(previousState);
    clearAppCache();
    invalidateDerivedDataCaches();
    activeCategoryId = previousActiveCategoryId;
    restoreUndoStateSnapshot(undoSnapshot);
    render();
    return;
  }
  clearUndoState();
  render();
  showAppToast("Obnovené", {
    tone: "success"
  });
}

function updateUndoButton() {
  if (!undoDeleteEl) return;
  undoDeleteEl.hidden = !lastDeleted;
}

function updateMenuVisibility() {
  if (!menuPanelEl) return;
  if (typeof document !== "undefined") {
    document.body.classList.toggle("app-main-menu-mode", !isFocusedView);
    document.body.classList.toggle("app-focused-mode", isFocusedView);
    document.body.classList.toggle("app-main-menu-categories-preview", !isFocusedView && mainMenuCategoriesPreviewVisible);
  }
  menuPanelEl.classList.toggle("is-hidden", isFocusedView);
  if (workspaceMainEl) {
    workspaceMainEl.classList.toggle("is-hidden", !isFocusedView);
  }
  if (workspaceLayoutEl) {
    workspaceLayoutEl.classList.toggle("workspace-layout--menu", !isFocusedView);
  }
  if (mainMenuQuickEl) {
    mainMenuQuickEl.hidden = !isFocusedView;
  }
  if (batchSowingQuickEl) {
    batchSowingQuickEl.hidden = !activeSyncCount(state.varieties);
  }
  if (batchMoveQuickEl) {
    batchMoveQuickEl.hidden = !activeSyncCount(state.varieties);
  }
  updateCatalogHeader();
  syncMobileTopStripVisibility();
  syncMobileToolbarScrollState();
}

